INSERT INTO `events` VALUES (20,'SPECIAL NON- WORKING HOLIDAY : ALL SAINT\'S DAY EVE','Malacañang has officially declared October 31, 2025, as an additional special non-working day across the Philippines through Proclamation No. 727.\r\n\r\nThe government made the declaration to allow Filipinos sufficient time to prepare for and observe All Saints’ Day and All Souls’ Day, collectively known as Undas or Kalag-Kalag.\r\n\r\nPresident Ferdinand R. Marcos Jr. signed the proclamation, ensuring that citizens can spend quality time with their families while honoring departed loved ones.','2025-10-31 00:00:00','2025-10-31 12:00:00','2025-10-30 07:29:53','2025-10-30 07:29:53','Holiday',NULL,'gerryca.joves.gj@sanden-rs.com'),(21,'Overview & Process of JSOX Audit (Sales) Physical Audit','Orientation & Overview of JSOX Physical Audit','2025-11-03 13:00:00','2025-11-03 14:30:00','2025-10-30 07:34:26','2025-10-30 07:34:26','Room','conference_room_1f','fernan.dichoso.cj@sanden-rs.com'),(22,'OPM (Management Division)','OPM (Management Division Team)','2025-11-14 13:00:00','2025-11-14 16:00:00','2025-10-30 07:36:37','2025-10-30 07:36:37','Room','conference_room_1f','fernan.dichoso.cj@sanden-rs.com'),(23,'Flash Report October Results','Flash Report with Ikeda san & Larry san','2025-11-06 10:00:00','2025-11-06 11:37:00','2025-10-30 07:39:06','2025-10-30 07:39:06','Room','meeting_room_1_2f_right','fernan.dichoso.cj@sanden-rs.com'),(24,'SDRS-SCP (Monthly Meeting)','SDRS/SCP (Monthly Meeting) with Ikeda san & Larry san','2025-11-19 09:00:00','2025-11-19 10:00:00','2025-10-30 07:43:59','2025-10-30 07:43:59','Room','meeting_room_1_2f_right','fernan.dichoso.cj@sanden-rs.com'),(26,'SCP INTRANET LAUNCH!','Announcement and Account/Access Provision','2025-10-30 15:00:00','2025-10-30 16:00:00','2025-10-30 07:48:41','2025-10-30 07:48:41','Events',NULL,'neil.olivera.no@sanden-rs.com'),(27,'Cash Flow Projection','Cash Flow Projection','2025-11-06 11:40:00','2025-11-06 12:00:00','2025-10-30 08:03:26